export const isArmstrongNumber = (input) => {
  const str = String(input);
  const numDigits = str.length;
  let sum = 0n;

  for (const digit of str) {
    sum += BigInt(digit) ** BigInt(numDigits);
  }

  return sum === BigInt(input);
};
